Here’s a TekAutomate Steps UI flow to set up CAN FD decode on B1 (CH2), configure search for CAN FD error frames, set edge trigger, enable FastFrame, acquire, then query timestamps, and save waveform and screenshot.

```json
{
  "steps": [
    {
      "type": "connect",
      "id": "connect_scope",
      "params": {
        "device_type": "SCOPE",
        "model_family": "MSO4/5/6 Series"
      }
    },
    {
      "type": "comment",
      "id": "comment_decode",
      "params": {
        "text": "Set up CAN FD decode on Bus1 (CH2), 500kbps nominal, 2Mbps data, ISO standard"
      }
    },
    {
      "type": "write",
      "id": "decode_setup",
      "params": {
        "command": "BUS:CANFD:STATE ON;BUS:CANFD:SOUR CH2;BUS:CANFD:BITR 500000;BUS:CANFD:DBITR 2000000;BUS:CANFD:ISO ON"
      }
    },
    {
      "type": "comment",
      "id": "comment_search",
      "params": {
        "text": "Set up search for CAN FD error frames on Bus1"
      }
    },
    {
      "type": "write",
      "id": "search_setup",
      "params": {
        "command": "SEARCH:MODE BUS;SEARCH:BUS CANFD1;SEARCH:CANFD:TYPE ERRF"
      }
    },
    {
      "type": "comment",
      "id": "comment_trigger",
      "params": {
        "text": "Set edge trigger on CH2 rising at 1.65V"
      }
    },
    {
      "type": "write",
      "id": "trigger_setup",
      "params": {
        "command": "TRIG:A:TYPE EDGE;TRIG:A:EDGE:SOU CH2;TRIG:A:EDGE:SLO RIS;TRIG:A:LEV1 1.65"
      }
    },
    {
      "type": "comment",
      "id": "comment_fastframe",
      "params": {
        "text": "Enable FastFrame, 500 frames, single sequence"
      }
    },
    {
      "type": "write",
      "id": "fastframe_setup",
      "params": {
        "command": "ACQ:NUMFRAMES 500;ACQ:STOPA SEQ;ACQ:STATE ON"
      }
    },
    {
      "type": "comment",
      "id": "comment_wait",
      "params": {
        "text": "Wait for acquisition to complete"
      }
    },
    {
      "type": "query",
      "id": "wait_acq_complete",
      "params": {
        "command": "*OPC?",
        "timeout": 30000
      }
    },
    {
      "type": "comment",
      "id": "comment_query_timestamps",
      "params": {
        "text": "Query FastFrame timestamps for all frames"
      }
    },
    {
      "type": "query",
      "id": "query_timestamps",
      "params": {
        "command": "ACQ:FRAMe:TIMestamp:ALL?",
        "timeout": 10000
      }
    },
    {
      "type": "comment",
      "id": "comment_save_waveform",
      "params": {
        "text": "Save CH2 waveform as binary"
      }
    },
    {
      "type": "save_waveform",
      "id": "save_ch2_waveform",
      "params": {
        "source": "CH2",
        "file_format": "BIN",
        "file_path": "D:/CH2_FastFrame.bin"
      }
    },
    {
      "type": "comment",
      "id": "comment_save_screenshot",
      "params": {
        "text": "Save screenshot"
      }
    },
    {
      "type": "save_screenshot",
      "id": "save_screenshot",
      "params": {
        "file_path": "D:/CANFD_FastFrame.png"
      }
    },
    {
      "type": "disconnect",
      "id": "disconnect_scope",
      "params": {}
    }
  ]
}
```

Notes:

- All SCPI commands are based on Tektronix MSO4/5/6 Series documentation. If any command is not accepted, please verify with your instrument’s manual.
- The `ACQ:FRAMe:TIMestamp:ALL?` query is used for FastFrame timestamps; if not supported, you may need to query each frame individually.
- File paths (`D:/...`) can be adjusted as needed for your instrument’s storage.
- The flow assumes Bus1 is CANFD1; adjust if your scope uses a different bus naming convention.

